// Function to find the shortest path using Dijkstra's algorithm
void dijkstra(int **graph, int *dist, int start, int n) {
    for (int i = 0; i < n; i++) {
        dist[i] = INF;
    }
    dist[start] = 0;
    int *visited = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < n; i++) {
        int min = INF, min_index;
        for (int j = 0; j < n; j++) {
            if (!visited[j] && dist[j] < min) {
                min = dist[j];
                min_index = j;
            }
        }
        visited[min_index] = 1;
        for (int j = 0; j < n; j++) {
            if (!visited[j] && graph[min_index][j] != 0 && dist[min_index] + graph[min_index][j] < dist[j]) {
                dist[j] = dist[min_index] + graph[min_index][j];
            }
        }
    }
    free(visited);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int **graph = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)malloc(N * sizeof(int));
        }
