            for (int j = 0; j < Ai; j++) {
                int weight;
                scanf("%d", &weight);
                if (j < Ai - 1) {
                    graph[i][i] += weight;
                } else {
                    graph[i][i] += weight;
                }
            }
        }
        for (int i = 0; i < N; i++) {
            int v1, v2, w;
            scanf("%d %d %d", &v1, &v2, &w);
            graph[i][(i + 1) % N] += w;
        }
        for (int i = 0; i < Q; i++) {
            int v1, c1, v2, c2;
            scanf("%d %d %d %d", &v1, &c1, &v2, &c2);
            int *dist = (int *)malloc(N * sizeof(int));
