#include <iostream>
#include <vector>
#include <limits>
#include <queue>
#include <utility>
#define INF INT_MAX
using namespace std;

// Function to find the shortest path using Dijkstra's algorithm
void dijkstra(vector<vector<int>> &graph, vector<int> &dist, int start, int n) {
    for (int i = 0; i < n; i++) {
        dist[i] = INF;
    }
    dist[start] = 0;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, start});
    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();
        for (int v = 0; v < n; v++) {
            if (graph[u][v] != 0 && dist[u] + graph[u][v] < dist[v]) {
                dist[v] = dist[u] + graph[u][v];
                pq.push({dist[v], v});
            }
        }
    }
}

