import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Arrays;
public class Main {
    static final int INF = Integer.MAX_VALUE;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[][] graph = new int[N][N];
            for (int i = 0; i < N; i++) {
                int Ai = sc.nextInt();
                for (int j = 0; j < Ai; j++) {
                    int weight = sc.nextInt();
                    if (j < Ai - 1) {
                        graph[i][i] += weight;
                    } else {
                        graph[i][i] += weight;
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                int v1 = sc.nextInt();
                int v2 = sc.nextInt();
                int w = sc.nextInt();
                graph[i][(i + 1) % N] += w;
            }
            for (int i = 0; i < Q; i++) {
                int v1 = sc.nextInt();
                int c1 = sc.nextInt();
                int v2 = sc.nextInt();
                int c2 = sc.nextInt();
                int[] dist = new int[N];
                Arrays.fill(dist, INF);
                dijkstra(graph, dist, c1 - 1, N);
                System.out.println(dist[c2 - 1]);
            }
        }
    }
    public static void dijkstra(int[][] graph, int[] dist, int start, int n) {
        dist[start] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[1] - b[1]);
        pq.offer(new int[] {start, 0});
        while (!pq.isEmpty()) {
            int[] u = pq.poll();
            for (int v = 0; v < n; v++) {
                if (graph[u[0]][v] != 0 && dist[u[0]] + graph[u[0]][v] < dist[v]) {
                    dist[v] = dist[u[0]] + graph[u[0]][v];
                    pq.offer(new int[] {v, dist[v]});
                }
            }
        }
    }
}

